const items = $input.all();

if (items.length === 0) {
  return {
    json: {
      ok: false,
      error: 'No se encontró ningún followup con ese id'
    }
  };
}

return {
  json: {
    ok: true,
    followup: items[0].json
  }
};

const body = $json.body || {};

const validStatuses = ['approved', 'edited', 'rejected'];
const status = body.status;
const followupId = body.followup_id;
const reviewedBy = body.reviewed_by ? String(body.reviewed_by).trim() : null;
const editedAction = body.edited_action ? String(body.edited_action).trim() : null;

const errors = [];

if (!followupId || typeof followupId !== 'string') {
  errors.push('followup_id es obligatorio y debe ser un string');
}

if (!validStatuses.includes(status)) {
  errors.push(`status debe ser uno de: ${validStatuses.join(', ')}`);
}

if (status === 'edited' && !editedAction) {
  errors.push('edited_action es obligatorio cuando status es "edited"');
}

if (!reviewedBy) {
  errors.push('reviewed_by es obligatorio');
}

if (errors.length > 0) {
  return {
    json: {
      valid: false,
      errors
    }
  };
}

return {
  json: {
    valid: true,
    followup_id: followupId,
    status,
    edited_action: editedAction,
    reviewed_by: reviewedBy
  }
};

