const parseJson = (value) => {
  try {
    const text = value?.output?.[0]?.content?.[0]?.text ?? value?.text ?? value;
    if (typeof text === 'object' && text !== null) return text;
    if (typeof text !== 'string') return {};
    return JSON.parse(text.replace(/```json/gi, '').replace(/```/g, '').trim());
  } catch (error) {
    return {};
  }
};

const data = parseJson($json);
const base = $('Consolidar Base Educativa').first().json || {};
const approvedContent = base.approved_content || [];
const availableTopics = Array.isArray(base.available_topics) ? base.available_topics : [];
const crm = $('Leer Estado CRM').first().json || {};
const userMessage = String($('Edit Fields').first().json.message?.content || '').trim();
const normalized = userMessage
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[¡!.,;:]+$/g, '');

if (base.request_type === 'LIST_APPROVED_CONTENT') {
  return {
    json: {
      interaction_type: 'LIST_APPROVED_CONTENT',
      supported: availableTopics.length > 0,
      topic: null,
      available_topics: availableTopics,
      source: null,
      level: 'BEGINNER',
      definition: '',
      explanation: '',
      advantages: [],
      disadvantages: [],
      risks: [],
      example: '',
      learning_path: [],
      quiz: [],
      recommended_followup: 'NONE',
      consent_flag: null,
      content_validated: true,
      unsupported_reason: availableTopics.length > 0 ? null : 'NO_APPROVED_CONTENT',
      total_approved_count: base.total_approved_count || 0,
      session_id: $('Edit Fields').first().json.session.id
    }
  };
}

const grantsConsent = /\b(si|autorizo|acepto|pueden contactarme|pueden guardar|guarden mi interes|doy mi consentimiento)\b/i.test(normalized)
  && !/\b(no|no autorizo|no acepto|no quiero|no guarden|no me contacten)\b/i.test(normalized);
const deniesConsent = /\b(no autorizo|no acepto|no quiero|no guarden|no me contacten|prefiero que no)\b/i.test(normalized);

let consentFlag = null;
if (grantsConsent) consentFlag = true;
if (deniesConsent) consentFlag = false;
if (typeof data.consent_flag === 'boolean' && consentFlag === null) consentFlag = data.consent_flag;

const sourceId = data.source?.content_id != null ? String(data.source.content_id) : null;
const approvedRecord = sourceId
  ? approvedContent.find((row) => String(row.id) === sourceId)
  : null;

const supported = data.supported === true && Boolean(approvedRecord);
let source = null;
if (supported) {
  source = {
    content_id: String(approvedRecord.id),
    organization: approvedRecord.source_org,
    document: approvedRecord.source_document,
    section: approvedRecord.source_section || '',
    version: approvedRecord.version || '',
    approved_by: approvedRecord.approved_by || '',
    approved_at: approvedRecord.approved_at || ''
  };
}

const topic = data.topic || crm.educational_topic || crm.topic_of_interest || null;
const interactionType = consentFlag !== null && !supported
  ? 'CONSENT_ONLY'
  : supported ? 'EDUCATION' : 'UNSUPPORTED';

let recommendedFollowup = supported ? data.recommended_followup : 'NONE';
let learningPath = Array.isArray(data.learning_path) ? data.learning_path.filter(Boolean).slice(0, 3) : [];
let quiz = Array.isArray(data.quiz) ? data.quiz.filter(Boolean).slice(0, 3) : [];

if (recommendedFollowup === 'QUIZ') {
  learningPath = [];
  if (quiz.length !== 3) recommendedFollowup = 'NONE';
} else if (recommendedFollowup === 'LEARNING_PATH') {
  quiz = [];
  if (learningPath.length < 2) recommendedFollowup = 'NONE';
} else {
  recommendedFollowup = 'NONE';
  learningPath = [];
  quiz = [];
}

return {
  json: {
    interaction_type: interactionType,
    supported,
    topic,
    available_topics: availableTopics,
    source,
    level: supported ? (data.level || 'BEGINNER') : 'BEGINNER',
    definition: supported ? (data.definition || '') : '',
    explanation: supported ? (data.explanation || '') : '',
    advantages: supported && Array.isArray(data.advantages) ? data.advantages : [],
    disadvantages: supported && Array.isArray(data.disadvantages) ? data.disadvantages : [],
    risks: supported && Array.isArray(data.risks) ? data.risks : [],
    example: supported ? (data.example || '') : '',
    learning_path: supported ? learningPath : [],
    quiz: supported ? quiz : [],
    recommended_followup: supported ? recommendedFollowup : 'NONE',
    consent_flag: consentFlag,
    content_validated: supported,
    unsupported_reason: supported ? null : ((base.total_approved_count || 0) === 0 ? 'NO_APPROVED_CONTENT' : 'NO_MATCHING_CONTENT'),
    total_approved_count: base.total_approved_count || 0,
    session_id: $('Edit Fields').first().json.session.id
  }
};

