const parseObject = (value) => {
  if (value && typeof value === 'object') return value;
  if (typeof value !== 'string') return {};
  try { return JSON.parse(value.replace(/```json/gi, '').replace(/```/g, '').trim()); }
  catch (error) { return {}; }
};

const normalizeText = (value) => String(value ?? '')
  .trim()
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '');

const parseMoney = (value) => {
  if (value === null || value === undefined || value === '') return null;
  if (typeof value === 'number') return Number.isFinite(value) ? value : null;

  let text = normalizeText(value)
    .replace(/usd|dolares?|dollars?|[$€]/g, '')
    .trim();

  let multiplier = 1;
  if (/\b(millon|millones|m)\b/.test(text)) multiplier = 1000000;
  else if (/\b(mil|k)\b/.test(text)) multiplier = 1000;

  text = text.replace(/\b(millon|millones|mil|k|m)\b/g, '').trim();
  const match = text.match(/-?\d[\d.,]*/);
  if (!match) return null;
  let numberText = match[0];

  const lastComma = numberText.lastIndexOf(',');
  const lastDot = numberText.lastIndexOf('.');

  if (lastComma >= 0 && lastDot >= 0) {
    // El último separador se considera decimal; el otro, miles.
    if (lastComma > lastDot) {
      numberText = numberText.replace(/\./g, '').replace(',', '.');
    } else {
      numberText = numberText.replace(/,/g, '');
    }
  } else if (lastComma >= 0 || lastDot >= 0) {
    const separator = lastComma >= 0 ? ',' : '.';
    const parts = numberText.split(separator);
    if (parts.length > 2 || (parts.length === 2 && parts[1].length === 3 && multiplier === 1)) {
      numberText = parts.join('');
    } else if (separator === ',') {
      numberText = numberText.replace(',', '.');
    }
  }

  const parsed = Number(numberText) * multiplier;
  return Number.isFinite(parsed) ? parsed : null;
};

const extractMoneyFromText = (message, requireInvestmentContext = false) => {
  const text = normalizeText(message);
  const patterns = [
    /(?:invertir|inversion|capital|destinar|monto|presupuesto)\D{0,25}(?:usd|\$)?\s*(\d[\d.,]*)\s*(millones?|millon|mil|k|m)?\s*(?:usd|\$|dolares?)?/i,
    /(?:usd|\$)\s*(\d[\d.,]*)\s*(millones?|millon|mil|k|m)?/i,
    /(\d[\d.,]*)\s*(millones?|millon|mil|k|m)?\s*(?:usd|\$|dolares?)/i,
  ];
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (!match) continue;
    if (requireInvestmentContext && !/(invertir|inversion|capital|destinar|monto|presupuesto|usd|\$|dolar)/i.test(match[0])) continue;
    const parsed = parseMoney(`${match[1]} ${match[2] || ''}`);
    if (parsed !== null) return parsed;
  }
  return null;
};

const orchestratorContainer = $('Edit Fields1').first().json || {};
const orchestrator = parseObject(orchestratorContainer.orquestador || orchestratorContainer);
const agents = Array.isArray(orchestrator.agents) ? orchestrator.agents : [];
const commercialRequested = agents.includes('COMERCIAL');
const sessionId = $('Edit Fields').first().json.session.id;
const currentMessage = $('Edit Fields').first().json.message?.content || '';
const crm = (() => { try { return $('Leer Estado CRM').first().json || {}; } catch (error) { return {}; } })();
const history = (() => {
  try { return $('Leer Historial Mensajes').all().map(i => i.json).filter(Boolean); }
  catch (error) { return []; }
})();
const lastAssistantMessage = [...history].reverse().find(i => i.role === 'assistant')?.content || '';

// Protección determinística: un turno educativo nunca modifica el perfil comercial.
if (!commercialRequested) {
  return {
    json: {
      budget: null,
      corporate_budget: null,
      operating_reserve: null,
      risk: null,
      goal: null,
      horizon: null,
      prospect_type: null,
      country: null,
      investment_experience: null,
      emergency_fund_status: null,
      company_size: null,
      decision_maker: null,
      priority: null,
      priority_score: null,
      summary: null,
      session_id: sessionId,
      commercial_skipped: true,
      deterministic_resolution: null
    }
  };
}

let parsedAgent;
try {
  const rawText = $json.output?.[0]?.content?.[0]?.text;
  parsedAgent = parseObject(rawText);
} catch (error) {
  parsedAgent = { database_updates: {}, lead: {}, conversation_summary: null };
}

const updates = parsedAgent.database_updates || {};
const lead = parsedAgent.lead || {};
const normalizedCurrent = normalizeText(currentMessage).replace(/[¡!.,;:]+$/g, '');
const normalizedLastAssistant = normalizeText(lastAssistantMessage);
const explicitYes = /^(si|correcto|exacto|asi es|de acuerdo|confirmo|afirmativo)$/.test(normalizedCurrent);

let prospectType = updates.prospect_type ?? lead.prospect_type ?? crm.prospect_type ?? null;
const looksB2B = prospectType === 'B2B' || /\bempresa|negocio|corporativo|tesoreria|gerencia|nomina|proveedores\b/i.test(normalizedCurrent);
if (!prospectType && looksB2B) prospectType = 'B2B';

let budget = parseMoney(updates.investment_budget);
let corporateBudget = parseMoney(updates.corporate_budget);
let operatingReserve = parseMoney(updates.operating_reserve);
let deterministicResolution = null;

// Respaldo determinístico para un monto explícito que el LLM no extrajo.
const explicitCurrentAmount = extractMoneyFromText(currentMessage, true);
if (budget === null && explicitCurrentAmount !== null && /\binvertir|inversion|capital|destinar\b/i.test(normalizedCurrent)) {
  budget = explicitCurrentAmount;
  deterministicResolution = 'investment_budget_from_current_message';
}

// En B2B, "quiero invertir X para mi empresa" ya define el presupuesto corporativo bajo evaluación.
// No se pide un segundo presupuesto salvo que el usuario diga explícitamente que son montos distintos.
if (looksB2B && corporateBudget === null) {
  if (budget !== null) {
    corporateBudget = budget;
    deterministicResolution = deterministicResolution || 'corporate_budget_synced_from_investment_budget';
  } else if (crm.corporate_budget !== null && crm.corporate_budget !== undefined) {
    corporateBudget = parseMoney(crm.corporate_budget);
  } else if (crm.investment_budget !== null && crm.investment_budget !== undefined) {
    corporateBudget = parseMoney(crm.investment_budget);
    deterministicResolution = deterministicResolution || 'corporate_budget_synced_from_crm_investment_budget';
  }
}

// Si el asistente preguntó explícitamente si un monto concreto era el presupuesto corporativo
// y el usuario respondió "sí", se confirma ese mismo monto y se avanza; nunca se repite la pregunta.
const lastAssistantAmount = extractMoneyFromText(lastAssistantMessage, false);
const confirmsCorporateBudget = explicitYes
  && /presupuesto corporativo/i.test(normalizedLastAssistant)
  && lastAssistantAmount !== null
  && /\b(es|son|corresponde|corresponden|tomaremos|referencia)\b/i.test(normalizedLastAssistant);
if (confirmsCorporateBudget && corporateBudget === null) {
  corporateBudget = lastAssistantAmount ?? parseMoney(crm.investment_budget);
  deterministicResolution = 'corporate_budget_confirmed_from_previous_question';
}

// Respaldo para la nueva pregunta de liquidez operativa.
if (operatingReserve === null
    && /nomina|proveedores|contingencias|quedar disponible|reserva operativa|fuera de la inversion/i.test(normalizedLastAssistant)) {
  const reserveFromCurrent = extractMoneyFromText(currentMessage, false);
  if (reserveFromCurrent !== null) {
    operatingReserve = reserveFromCurrent;
    deterministicResolution = deterministicResolution || 'operating_reserve_from_current_reply';
  }
}

return {
  json: {
    budget,
    corporate_budget: corporateBudget,
    operating_reserve: operatingReserve,
    risk: updates.risk_profile ?? null,
    goal: updates.financial_goal ?? null,
    horizon: updates.investment_horizon ?? null,
    prospect_type: prospectType,
    country: updates.country ?? null,
    investment_experience: updates.investment_experience ?? null,
    emergency_fund_status: updates.emergency_fund_status ?? null,
    company_size: (() => {
  const value = updates.company_size;

  if (
    value === null ||
    value === undefined ||
    value === ''
  ) {
    return null;
  }

  const text = String(value).trim();

  return /^\d+$/.test(text)
    ? `${text} personas`
    : text;
})(),
    decision_maker: updates.decision_maker ?? null,
    priority: updates.lead_priority ?? lead.priority ?? null,
    priority_score: parseMoney(updates.priority_score ?? lead.priority_score),
    summary: parsedAgent.conversation_summary ?? null,
    session_id: sessionId,
    commercial_skipped: false,
    deterministic_resolution: deterministicResolution
  }
};

// ============================================================
// CONSOLIDACIÓN SEGURA + CONTINUIDAD + COHERENCIA DE MONTOS
// ============================================================
const parseOpenAIJson = (nodeName) => {
  try {
    const raw = $(nodeName).first().json;
    if (!raw) return null;
    if (raw.profile || raw.database_updates || raw.supported !== undefined || raw.intent || raw.agents || raw.interaction_type) return raw;
    const text = raw.output?.[0]?.content?.[0]?.text ?? raw.text ?? raw.content ?? null;
    if (typeof text !== 'string') return raw;
    return JSON.parse(text.replace(/```json/gi, '').replace(/```/g, '').trim());
  } catch (error) { return null; }
};
const safeNode = (name) => { try { return $(name).first().json || null; } catch (error) { return null; } };
const firstKnown = (...values) => values.find((value) => value !== undefined && value !== null && value !== '') ?? null;
const normalize = (value) => String(value ?? '').trim().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const formatUSD = (value) => {
  const n = Number(value);
  return Number.isFinite(n) ? `$${n.toLocaleString('en-US', { maximumFractionDigits: 2 })}` : null;
};

const orchestrator = parseOpenAIJson('Orquestador') || safeNode('Edit Fields1')?.orquestador || {};
const requestedAgents = Array.isArray(orchestrator.agents) ? orchestrator.agents : [];
const commercialRequested = requestedAgents.includes('COMERCIAL');
const tutorRequested = requestedAgents.includes('TUTOR');
const educationalOnly = tutorRequested && !commercialRequested;

const emptyCommercial = { profile: {}, lead: {}, conversation_summary: null, missing_information: [], database_updates: {} };
const commercialRaw = parseOpenAIJson('Agente Comercial') || emptyCommercial;
const commercial = commercialRequested ? commercialRaw : emptyCommercial;
const persisted = safeNode('Code in JavaScript1') || {};
const education = safeNode('Code in JavaScript2') || parseOpenAIJson('Agente Tutor');
const crm = safeNode('Leer Estado CRM') || {};
const userMessage = $('Edit Fields').first().json.message?.content || '';

const history = $('Leer Historial Mensajes').all()
  .map((item) => ({ role: item.json.role, content: item.json.content }))
  .filter((item) => item.role && item.content);
const lastAssistantMessage = [...history].reverse().find((item) => item.role === 'assistant')?.content || '';

const updates = commercial.database_updates || {};
const profile = commercial.profile || {};
const known = {
  investment_budget: firstKnown(persisted.budget, updates.investment_budget, profile.investment_budget, crm.investment_budget),
  risk_profile: firstKnown(persisted.risk, updates.risk_profile, profile.risk_profile, crm.risk_profile),
  financial_goal: firstKnown(persisted.goal, updates.financial_goal, profile.financial_goal, crm.financial_goal),
  investment_horizon: firstKnown(persisted.horizon, updates.investment_horizon, profile.investment_horizon, crm.investment_horizon),
  emergency_fund_status: firstKnown(persisted.emergency_fund_status, updates.emergency_fund_status, profile.emergency_fund_status, crm.emergency_fund_status),
  country: firstKnown(persisted.country, updates.country, profile.country, crm.country),
  investment_experience: firstKnown(persisted.investment_experience, updates.investment_experience, profile.investment_experience, profile.experience, crm.investment_experience),
  company_size: firstKnown(persisted.company_size, updates.company_size, profile.company_size, crm.company_size),
  decision_maker: firstKnown(persisted.decision_maker, updates.decision_maker, profile.decision_maker, crm.decision_maker),
  corporate_budget: firstKnown(persisted.corporate_budget, updates.corporate_budget, profile.corporate_budget, crm.corporate_budget),
  operating_reserve: firstKnown(persisted.operating_reserve, updates.operating_reserve, profile.operating_reserve, crm.operating_reserve),
  asset_price: firstKnown(profile.asset_price, profile.price, profile.precio_bien),
  down_payment: firstKnown(profile.down_payment, profile.entrada, profile.pago_inicial),
  financing_term: firstKnown(profile.financing_term, profile.plazo_financiamiento),
  interest_rate: firstKnown(profile.interest_rate, profile.tasa_interes),
  prospect_type: firstKnown(persisted.prospect_type, updates.prospect_type, commercial.lead?.prospect_type, profile.prospect_type, crm.prospect_type)
};

const currentText = normalize(userMessage);
const isB2B = commercialRequested && (known.prospect_type === 'B2B' || /\bempresa|negocio|corporativo|tesoreria|gerencia|nomina|proveedores\b/i.test(currentText));

// Regla determinística: un monto explícitamente destinado a invertir por una empresa
// también es el presupuesto corporativo bajo evaluación, salvo que el usuario diferencie ambos.
if (isB2B && known.corporate_budget === null && known.investment_budget !== null) {
  known.corporate_budget = known.investment_budget;
}

// Reflejamos la resolución determinística dentro de la vista comercial del turno.
commercial.database_updates = { ...(commercial.database_updates || {}) };
if (persisted.budget !== null && persisted.budget !== undefined) commercial.database_updates.investment_budget = persisted.budget;
if (persisted.corporate_budget !== null && persisted.corporate_budget !== undefined) commercial.database_updates.corporate_budget = persisted.corporate_budget;
if (persisted.operating_reserve !== null && persisted.operating_reserve !== undefined) commercial.database_updates.operating_reserve = persisted.operating_reserve;
if (persisted.prospect_type) commercial.database_updates.prospect_type = persisted.prospect_type;

const aliases = {
  budget: 'investment_budget', presupuesto: 'investment_budget', capital: 'investment_budget',
  risk: 'risk_profile', riesgo: 'risk_profile', goal: 'financial_goal', objetivo: 'financial_goal',
  horizon: 'investment_horizon', horizonte: 'investment_horizon', experience: 'investment_experience',
  experiencia: 'investment_experience', 'fondo de emergencia': 'emergency_fund_status',
  'tamano de empresa': 'company_size', 'tamaño de empresa': 'company_size',
  'responsable de decision': 'decision_maker', 'presupuesto corporativo': 'corporate_budget',
  'reserva operativa': 'operating_reserve', 'liquidez operativa': 'operating_reserve',
  'precio del bien': 'asset_price', entrada: 'down_payment', plazo: 'financing_term', tasa: 'interest_rate'
};
const normalizeField = (field) => aliases[normalize(field)] || field;

let missing = commercialRequested && Array.isArray(commercial.missing_information)
  ? commercial.missing_information.map(normalizeField)
  : [];
missing = [...new Set(missing)].filter((field) => !(field in known) || known[field] === null);

const hasStoredInvestmentProfile = Boolean(crm.investment_budget || crm.financial_goal || crm.investment_horizon || crm.risk_profile);
const hasStoredFinancingProfile = Boolean(profile.asset_price || profile.down_payment || profile.financing_term);
const looksLikeInvestment = commercialRequested && (/\binvertir|inversion|capital|rentabilizar|hacer crecer|portafolio\b/i.test(currentText) || hasStoredInvestmentProfile || isB2B);
const looksLikeFinancing = commercialRequested && (/\bcomprar|financiar|credito|prestamo|hipoteca|casa|vivienda|carro|vehiculo|moto\b/i.test(currentText) || hasStoredFinancingProfile) && !looksLikeInvestment;

const priority = isB2B
  ? ['company_size', 'decision_maker', 'corporate_budget', 'operating_reserve']
  : looksLikeFinancing
    ? ['asset_price', 'down_payment', 'financing_term', 'interest_rate']
    : ['investment_horizon', 'risk_profile', 'financial_goal', 'emergency_fund_status', 'investment_budget'];

if (commercialRequested && (looksLikeInvestment || looksLikeFinancing || isB2B)) {
  for (const field of priority) if (known[field] === null && !missing.includes(field)) missing.push(field);
} else if (!commercialRequested) {
  missing = [];
}

// Nunca pedir corporate_budget si ya existe investment_budget para un B2B.
if (isB2B && known.investment_budget !== null) {
  missing = missing.filter(field => field !== 'corporate_budget');
}
commercial.missing_information = missing;
const nextMissingField = commercialRequested ? (priority.find((field) => missing.includes(field)) || missing[0] || null) : null;

const hasNewData = commercialRequested && (
  Object.keys(commercial.database_updates || {}).some((key) => commercial.database_updates[key] !== undefined && commercial.database_updates[key] !== null)
  || Boolean(persisted.deterministic_resolution)
);
const profileComplete = priority.every((field) => known[field] !== null || field === 'interest_rate');
const profileAlreadyConfirmed = commercialRequested && !hasNewData && profileComplete && (looksLikeInvestment || looksLikeFinancing || isB2B);

const normalizedMessage = normalize(userMessage).replace(/[¡!.,;:]+$/g, '');
const explicitAcceptance = /^(si|si por favor|por favor|dale|de acuerdo|ok|okay|hazlo|procede|continua|adelante|ayudame con eso|haz eso|correcto|exacto)$/i.test(normalizedMessage);
const previousAssistantOfferedAction = /\b(puedo|podemos|te preparo|te explico|te muestro|te ayudo|quieres que|deseas que|avanzamos|continuamos)\b/i.test(lastAssistantMessage);
const forceDeliveryNow = explicitAcceptance && previousAssistantOfferedAction;
const ambiguousFollowup = /^(¿?\?+|que|como|no entiendo|no entendi|explicame|como asi|a que te refieres)$/i.test(normalizedMessage);
const greetingOnly = /^(hola|buenas|buenos dias|buenas tardes|buenas noches|hey)$/i.test(normalizedMessage);
const thanksOnly = /^(gracias|muchas gracias|gracias ya entendi|ya entendi|entendido)$/i.test(normalizedMessage);
const consentResponse = education?.interaction_type === 'CONSENT_ONLY';

const corporateBudgetNumber = Number(known.corporate_budget);
const operatingReserveNumber = Number(known.operating_reserve);
const netDeployableCapital = Number.isFinite(corporateBudgetNumber) && Number.isFinite(operatingReserveNumber)
  ? Math.max(0, corporateBudgetNumber - operatingReserveNumber)
  : null;

const lastQuestionWasDuplicateCorporateBudget = isB2B
  && /presupuesto corporativo/i.test(normalize(lastAssistantMessage))
  && known.corporate_budget !== null;

return {
  json: {
    user_message: userMessage,
    intent: orchestrator.intent || null,
    requested_agents: requestedAgents,
    commercial_requested: commercialRequested,
    educational_only: educationalOnly,
    commercial,
    education,
    crm,
    known_profile: known,
    canonical_amounts: {
      investment_budget: known.investment_budget,
      investment_budget_display: formatUSD(known.investment_budget),
      corporate_budget: known.corporate_budget,
      corporate_budget_display: formatUSD(known.corporate_budget),
      operating_reserve: known.operating_reserve,
      operating_reserve_display: formatUSD(known.operating_reserve)
    },
    derived_profile: {
      net_deployable_capital: netDeployableCapital,
      net_deployable_capital_display: formatUSD(netDeployableCapital)
    },
    missing_information: missing,
    next_missing_field: nextMissingField,
    profile_already_confirmed: profileAlreadyConfirmed,
    forzar_entrega_ahora: forceDeliveryNow,
    ambiguous_followup: ambiguousFollowup,
    greeting_only: greetingOnly,
    thanks_only: thanksOnly,
    consent_response: consentResponse,
    last_assistant_message: lastAssistantMessage,
    last_question_was_duplicate_corporate_budget: lastQuestionWasDuplicateCorporateBudget,
    deterministic_resolution: persisted.deterministic_resolution || null,
    active_financial_context: commercialRequested && (looksLikeInvestment || looksLikeFinancing || isB2B)
  }
};

