const normalize = (value) => String(value || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '');

const parseObject = (value) => {
  if (value && typeof value === 'object') return value;
  if (typeof value !== 'string') return {};
  try { return JSON.parse(value.replace(/```json/gi, '').replace(/```/g, '').trim()); }
  catch (error) { return {}; }
};

const message = $('Edit Fields').first().json.message?.content || '';
const crm = $('Leer Estado CRM').first().json || {};
const orchestratorContainer = $('Edit Fields1').first().json || {};
const orchestrator = parseObject(orchestratorContainer.orquestador || orchestratorContainer);
const normalizedMessage = normalize(message);

const listRequest = orchestrator.intent === 'LIST_APPROVED_CONTENT'
  || /(?:que|cuales|lista|mostrar|dime).*(?:contenidos|temas|materiales|fuentes).*(?:aprobados|disponibles)/i.test(normalizedMessage)
  || /(?:sobre que|de que).*(?:puedes ensenar|puedes explicar|tienes contenido)/i.test(normalizedMessage);

const allRows = $input.all()
  .map((item) => item.json || {})
  .filter((row) => row.id && row.topic && row.content && row.source_document);

const seen = new Set();
const availableTopics = [];
for (const row of allRows) {
  const key = normalize(`${row.topic}|${row.title}|${row.source_document}|${row.version || ''}`);
  if (seen.has(key)) continue;
  seen.add(key);
  availableTopics.push({
    content_id: String(row.id),
    topic: row.topic,
    title: row.title || row.topic,
    organization: row.source_org || '',
    document: row.source_document,
    section: row.source_section || '',
    version: row.version || ''
  });
}

if (listRequest) {
  return {
    json: {
      request_type: 'LIST_APPROVED_CONTENT',
      approved_content: [],
      approved_content_count: 0,
      total_approved_count: allRows.length,
      available_topics: availableTopics.slice(0, 30)
    }
  };
}

const context = normalize([message, crm.educational_topic, crm.topic_of_interest].filter(Boolean).join(' '));
const tokens = new Set(context.split(/[^a-z0-9]+/).filter((token) => token.length >= 3));

const rows = allRows
  .map((row) => {
    const keywords = Array.isArray(row.keywords) ? row.keywords : [];
    const searchable = normalize([row.topic, row.title, ...keywords].join(' '));
    let score = 0;
    if (context.includes(normalize(row.topic))) score += 10;
    for (const keyword of keywords) {
      if (context.includes(normalize(keyword))) score += 5;
    }
    for (const token of tokens) {
      if (searchable.includes(token)) score += 1;
    }
    return { ...row, relevance_score: score };
  })
  .filter((row) => row.relevance_score > 0)
  .sort((a, b) => b.relevance_score - a.relevance_score)
  .slice(0, 5);

return {
  json: {
    request_type: 'EXPLAIN_TOPIC',
    approved_content: rows,
    approved_content_count: rows.length,
    total_approved_count: allRows.length,
    available_topics: availableTopics.slice(0, 30)
  }
};

const context = $('Code in JavaScript').first().json || {};
const row = $input.first()?.json || {};

const configuredQuestion = row.question_text
  ? {
      field_name: row.field_name,
      question_text: row.question_text,
